pub trait IngestProgress: Send + Sync {
    fn log(&self, msg: &str);
}
impl IngestProgress for PrintProgress {
    fn log(&self, msg: &str) {
        println!("{msg}");
    }
}
fn log(&self, msg: &str) {
        println!("{msg}");
    }
impl IngestProgress for TracingProgress {
    fn log(&self, msg: &str) {
        tracing::info!("{msg}");
    }
}
